import{_ as a,o as i,c as o,ag as t}from"./chunks/framework.DTiDeF2Q.js";const u=JSON.parse('{"title":"Aliasy Tmux | Dotfiles (PL)","titleTemplate":":title","description":"Skrocone polecenia tmux. Przeglad dla Dotfiles v0.2.495. Kompatybilny z macOS, Linux i WSL przez Dotfiles.","frontmatter":{"title":"Aliasy Tmux | Dotfiles","description":"Skrocone polecenia tmux. Przeglad dla Dotfiles v0.2.495. Kompatybilny z macOS, Linux i WSL przez Dotfiles.","lang":"pl-PL","author":"Sebastien Rousseau","lastUpdated":true,"image":"/logo.png","imageAlt":"Aliasy Tmux | Dotfiles preview","canonical":"/pl/aliases/tmux/","robots":"index, follow","draft":false,"noindex":false,"sitemap":true,"breadcrumbTitle":"Aliasy Tmux","pageType":"docs","schemaType":"WebPage","permalink":"/pl/aliases/tmux/"},"headers":[],"relativePath":"pl/aliases/tmux/index.md","filePath":"pl/aliases/tmux/index.md","lastUpdated":1773010926000}'),l={name:"pl/aliases/tmux/index.md"};function s(n,e,c,d,r,p){return i(),o("div",null,[...e[0]||(e[0]=[t('<h1 id="aliasy-tmux" tabindex="-1">Aliasy Tmux <a class="header-anchor" href="#aliasy-tmux" aria-label="Permalink to &quot;Aliasy Tmux&quot;">​</a></h1><p>Skrocone polecenia tmux.</p><p>Ta strona przedstawia jedna grupe aliasow i jej typowe skroty polecen. Przeczytaj ja najpierw, aby zrozumiec konwencje nazewnictwa, oczekiwane dane wejsciowe i bezpieczne wzorce wykonywania. Nastepnie otworz dodatek referencyjny, aby zobaczyc pelny spis polecen i dokladna skladnie. Te aliasy redukuja powtarzalne wpisywanie i zapewniaja spojne zachowanie przeplywy pracy na macOS, Linux i WSL.</p><h2 id="kiedy-uzywac" tabindex="-1">Kiedy uzywac <a class="header-anchor" href="#kiedy-uzywac" aria-label="Permalink to &quot;Kiedy uzywac&quot;">​</a></h2><p>Uzyj tej strony przed codziennym uzywaniem powloki, gdy potrzebujesz przewidywalnych wzorcow polecen.</p><h2 id="co-zawiera" tabindex="-1">Co zawiera <a class="header-anchor" href="#co-zawiera" aria-label="Permalink to &quot;Co zawiera&quot;">​</a></h2><ul><li>Aliasy: 11</li><li>Funkcje pomocnicze: 1</li><li>Pliki zrodlowe: 1</li></ul><h2 id="szybkie-przyklady" tabindex="-1">Szybkie przyklady <a class="header-anchor" href="#szybkie-przyklady" aria-label="Permalink to &quot;Szybkie przyklady&quot;">​</a></h2><ul><li><code>tma</code> -&gt; <code>&#39;tmux attach-session&#39; # Dolacz do ostatniej sesji</code></li><li><code>tmat</code> -&gt; <code>&#39;tmux attach-session -t&#39; # Dolacz do konkretnej sesji</code></li><li><code>tmi</code> -&gt; <code>&#39;tmux info&#39; # Pokaz informacje tmux</code></li><li><code>tmka</code> -&gt; <code>&#39;tmux kill-server&#39; # Zamknij wszystkie sesje (serwer)</code></li><li><code>tmks</code> -&gt; <code>&#39;tmux kill-session -a&#39; # Zamknij wszystkie sesje oprocz biezacej</code></li><li><code>tml</code> -&gt; <code>&#39;tmux list-sessions&#39; # Lista wszystkich sesji</code></li><li><code>tmlp</code> -&gt; <code>&#39;tmux list-panes&#39; # Lista paneli</code></li><li><code>tmls</code> -&gt; <code>&#39;tmux list-windows&#39; # Lista okien</code></li><li><code>tmn</code> -&gt; <code>&#39;tmux new-session&#39; # Nowa sesja bez nazwy</code></li><li><code>tmr</code> -&gt; <code>&#39;tmux source ~/.dotfiles/lib/configurations/tmux/tmux&#39; # Przeladuj konfiguracje</code></li><li><code>tms</code> -&gt; <code>&#39;tmux new-session -s&#39; # Nowa nazwana sesja</code></li></ul><h2 id="nastepny-krok" tabindex="-1">Nastepny krok <a class="header-anchor" href="#nastepny-krok" aria-label="Permalink to &quot;Nastepny krok&quot;">​</a></h2><p>Otworz pelna liste:</p>',11)])])}const y=a(l,[["render",s]]);export{u as __pageData,y as default};
